// Layout.js
import React from "react";
import Sidebar from "./components/Sidebar";
import Navbar from "./components/Navbar";
import "./Layout.css";

const Layout = ({ children }) => {
    return (
        <>
            <Navbar />
            <div className="layout-container">
                <Sidebar />
                <main className="main-content">
                    {children}
                </main>
            </div>
        </>
    );
};

export default Layout;
